    message: ""
  });
  const [status, setStatus] = useState<"idle" | "submitting" | "success">("idle");
  const [logs, setLogs] = useState<string[]>([]);

  const toggleService = (id: string) => {
    setSelectedServices(prev => 
      prev.includes(id) ? prev.filter(s => s !== id) : [...prev, id]
    );
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.message) return;

    setStatus("submitting");
    setLogs(["[SYS] COMPILING SERVICE SELECTIONS...", `[SYS] SELECTED_IDS: [${selectedServices.join(", ")}]`]);

    await new Promise(resolve => setTimeout(resolve, 800));
    setLogs(prev => [...prev, "[SEC] ENCRYPTING DATA TRANSMISSION PACKETS...", "[NET] NEGOTIATING EDGE ROUTER HANDSHAKE..."]);

    await new Promise(resolve => setTimeout(resolve, 850));
    setLogs(prev => [...prev, "[NET] SECURE HANDSHAKE COMPLETED // UPLOAD ACTIVE", "[SYS] WRITING TRANSMISSION FILE TO CORE SYSTEM..."]);

    await new Promise(resolve => setTimeout(resolve, 900));
    setStatus("success");
    setLogs(prev => [...prev, "Γ£ô SUCCESS // TRANSMISSION CONFIRMED // ID: XO_PARTNER_" + Math.floor(Math.random() * 89999 + 10000)]);
  };

  const resetForm = () => {
    setFormData({ name: "", email: "", org: "", message: "" });
    setSelectedServices([]);
    setStatus("idle");
    setLogs([]);
  };

  return (
    <section id="partner" className="w-full relative py-28 px-4 md:px-8 bg-[#0A0A0C] border-t border-[#1E293B]/30 bg-grid-blueprint overflow-hidden">
      {/* Blueprint Outer Frame Corners */}
      <div className="absolute top-12 left-12 right-12 bottom-12 border border-white/[0.01] pointer-events-none rounded-2xl hidden lg:block" />

      {/* Decorative Blur Ambient Elements */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] rounded-full bg-gradient-to-tr from-[#3B82F6]/3 to-[#F59E0B]/3 blur-[140px] pointer-events-none" />

      <div className="relative z-10 max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-16 items-start">

        {/* ==========================================
            LEFT COLUMN: BRAND DISCOVERY COPY
            ========================================== */}
        <div className="lg:col-span-5 flex flex-col justify-between h-full gap-8">
          <div className="space-y-6">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full border border-[#F59E0B]/20 bg-[#F59E0B]/5 text-[10px] font-semibold tracking-widest text-[#F59E0B] uppercase">
              <Sparkles size={10} className="animate-pulse" />
              Partnership Workspace Active
            </div>

            <h2 className="text-3xl md:text-5xl font-extrabold tracking-tight text-white leading-[1.1]">
              Let's craft the <br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-white via-zinc-200 to-zinc-400">
                systems of tomorrow
              </span> <br />
              together.
            </h2>

            <p className="text-sm text-zinc-400 leading-relaxed font-light">
              Whether you need high-fidelity custom enterprise software systems engineered from ground zero, complex SaaS product launches, edge integrations, or premium commercial branding cinematography from our visuals lab, MITRIXO is your primary partner.
            </p>

            <p className="text-sm text-zinc-400 leading-relaxed font-light">
              Select the capabilities required, submit your blueprint request, and initialize an elite engineering alignment call with our development and creative core staff.
            </p>
          </div>

          {/* Value Stats Metric Panel */}
          <div className="border border-white/[0.05] rounded-xl p-5 bg-[#111113]/30 grid grid-cols-3 gap-4 divide-x divide-white/[0.05] font-mono text-center">
            <div>
              <span className="block text-[8px] text-zinc-500 tracking-widest uppercase">SYS UPTIME</span>
              <span className="block text-sm font-bold text-white mt-1">99.99%</span>
              <span className="text-[8px] text-emerald-400">Production SLA</span>
            </div>
            <div className="pl-4">
              <span className="block text-[8px] text-zinc-500 tracking-widest uppercase">CORE FPS</span>
              <span className="block text-sm font-bold text-white mt-1">120 FPS</span>
              <span className="text-[8px] text-brand-blueprint">Locked Speed</span>
            </div>
            <div className="pl-4">
              <span className="block text-[8px] text-zinc-500 tracking-widest uppercase">FILM CAPTURE</span>
              <span className="block text-sm font-bold text-white mt-1">8K RAW</span>
              <span className="text-[8px] text-[#F59E0B]">Cinematic Red</span>
            </div>
          </div>
        </div>

        {/* ==========================================
            RIGHT COLUMN: HIGH-FIDELITY FORM CARD
            ========================================== */}
        <div className="lg:col-span-7 w-full">
          <div className="relative rounded-2xl border border-white/[0.05] bg-[#111113]/40 backdrop-blur-xl p-6 md:p-8 shadow-2xl overflow-hidden">

            {/* Blueprint Grid Lines */}
            <div className="absolute inset-0 bg-grid-blueprint opacity-[0.2] pointer-events-none" />

            {/* Corner Crosshairs */}
            <div className="absolute top-2 left-2 w-2 h-2 border-t border-l border-white/20" />
            <div className="absolute top-2 right-2 w-2 h-2 border-t border-r border-white/20" />
            <div className="absolute bottom-2 left-2 w-2 h-2 border-b border-l border-white/20" />
            <div className="absolute bottom-2 right-2 w-2 h-2 border-b border-r border-white/20" />

            <AnimatePresence mode="wait">
              {status !== "success" ? (
                <motion.form
                  key="form"
                  onSubmit={handleSubmit}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="space-y-6 relative z-10"
                >
                  {/* Service selector pills */}
                  <div className="space-y-3">
                    <label className="block text-[10px] font-mono tracking-widest text-zinc-500 uppercase">
                      [ Select Required Capabilities ]
                    </label>
                    <div className="flex flex-wrap gap-2.5">
                      {SERVICES.map(service => {
                        const isSelected = selectedServices.includes(service.id);
                        return (
                          <button
                            key={service.id}
                            type="button"
                            onClick={() => toggleService(service.id)}
                            className={`px-3 py-1.5 rounded-lg border text-xs tracking-wider transition-all font-mono select-none ${
                              isSelected
                                ? "bg-[#3B82F6]/10 border-[#3B82F6] text-white font-bold"
                                : "bg-white/[0.01] border-white/[0.05] text-zinc-400 hover:border-zinc-700 hover:text-zinc-200"
                            }`}
                          >
                            {service.name}
                          </button>
                        );
                      })}
                    </div>
                  </div>

                  {/* Standard Text Inputs */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                    {/* Name input */}
                    <div className="space-y-2">
                      <label className="block text-[10px] font-mono tracking-widest text-zinc-500 uppercase">
                        Name *
                      </label>
                      <div className="relative group/field">
                        <input
                          type="text"
                          name="name"
                          required
                          value={formData.name}
                          onChange={handleInputChange}
                          disabled={status === "submitting"}
                          placeholder="Michael Magdy"
                          className="w-full bg-brand-dark/40 border border-white/[0.04] focus:border-[#3B82F6] rounded-lg px-4 py-3 text-sm text-white placeholder-zinc-600 focus:outline-none transition-all"
                        />
                      </div>
                    </div>

                    {/* Email input */}
                    <div className="space-y-2">
                      <label className="block text-[10px] font-mono tracking-widest text-zinc-500 uppercase">
                        Email Address *
                      </label>
                      <input
                        type="email"
                        name="email"
                        required
                        value={formData.email}
                        onChange={handleInputChange}
                        disabled={status === "submitting"}
                        placeholder="michael@mitrixo.com"
                        className="w-full bg-brand-dark/40 border border-white/[0.04] focus:border-[#3B82F6] rounded-lg px-4 py-3 text-sm text-white placeholder-zinc-600 focus:outline-none transition-all"
                      />
                    </div>
                  </div>

                  {/* Organization input */}
                  <div className="space-y-2">
                    <label className="block text-[10px] font-mono tracking-widest text-zinc-500 uppercase">
                      Organization / Company
                    </label>
                    <input
                      type="text"
                      name="org"
                      value={formData.org}
                      onChange={handleInputChange}
                      disabled={status === "submitting"}
                      placeholder="Mitrixo Studio Inc."
                      className="w-full bg-brand-dark/40 border border-white/[0.04] focus:border-[#3B82F6] rounded-lg px-4 py-3 text-sm text-white placeholder-zinc-600 focus:outline-none transition-all"
                    />
                  </div>

                  {/* Message Input */}
                  <div className="space-y-2">
                    <label className="block text-[10px] font-mono tracking-widest text-zinc-500 uppercase">
                      Project Description *
                    </label>
                    <textarea
                      name="message"
                      required
                      rows={4}
                      value={formData.message}
                      onChange={handleInputChange}
                      disabled={status === "submitting"}
                      placeholder="Explain your platform requirements, technical scopes, and launch schedules..."
                      className="w-full bg-brand-dark/40 border border-white/[0.04] focus:border-[#3B82F6] rounded-lg px-4 py-3 text-sm text-white placeholder-zinc-600 focus:outline-none transition-all resize-none"
                    />
                  </div>

                  {/* Dynamic Technical terminal progress display during submissions */}
                  {status === "submitting" && (
                    <div className="border border-white/[0.04] bg-[#0A0A0C]/90 rounded-lg p-3 space-y-1 font-mono text-[9px] text-zinc-400">
                      <div className="flex items-center justify-between text-zinc-500 border-b border-white/[0.02] pb-1.5 mb-1.5 uppercase tracking-widest">
                        <span className="flex items-center gap-1.5"><Terminal size={10} /> Ingress Logs</span>
                        <span className="text-[#3B82F6]">ACTIVE Upload</span>
                      </div>
                      {logs.map((log, idx) => (
                        <div key={idx} className="flex gap-1 items-start">
                          <span className="text-[#3B82F6] select-none">&gt;</span>
                          <span className="leading-3">{log}</span>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Action Button */}
                  <button
                    type="submit"
                    disabled={status === "submitting" || !formData.name || !formData.email || !formData.message}
                    className="w-full flex items-center justify-center gap-2.5 py-4 rounded-xl font-medium tracking-widest text-white border border-[#3B82F6]/30 bg-gradient-to-r from-[#3B82F6]/5 to-[#F59E0B]/5 hover:from-[#3B82F6]/10 hover:to-[#F59E0B]/10 hover:border-[#3B82F6] transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed group/btn cursor-pointer font-mono text-xs uppercase"
                  >
                    {status === "submitting" ? (
                      <>
                        <RefreshCw size={14} className="animate-spin text-[#3B82F6]" />
                        TRANSMITTING SYSTEM REQUEST...
                      </>
                    ) : (
                      <>
                        Initialize Partnership Alignment
                        <Send size={14} className="text-zinc-400 group-hover/btn:translate-x-1 group-hover/btn:text-[#3B82F6] transition-all" />
                      </>
                    )}
                  </button>

                </motion.form>
              ) : (
                <motion.div
                  key="success"
                  initial={{ opacity: 0, scale: 0.98 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.98 }}
                  className="relative z-10 flex flex-col justify-between py-6 px-2 min-h-[360px] text-center font-mono"
                >
                  <div className="flex flex-col items-center justify-center gap-4 flex-1">
                    <div className="w-16 h-16 rounded-full border border-emerald-500/20 bg-emerald-500/10 flex items-center justify-center shadow-lg relative overflow-hidden group">
                      <CheckCircle2 className="w-8 h-8 text-emerald-400" />
                    </div>

                    <div className="space-y-2 mt-2">
                      <h3 className="text-lg font-bold text-white tracking-wide uppercase">
                        TRANSMISSION SECURED
                      </h3>
                      <p className="text-xs text-zinc-500 max-w-sm mx-auto font-sans leading-relaxed font-light">
                        Your partnership system request has been encrypted and compiled into our core edge workspace. Our staff will review your metrics and respond shortly.
                      </p>
                    </div>
                  </div>

                  {/* Terminal final ledger logs */}
                  <div className="border border-white/[0.04] bg-[#0A0A0C]/90 rounded-lg p-3 space-y-1 font-mono text-[9px] text-zinc-400 text-left mb-6 max-h-[140px] overflow-y-auto">
                    <div className="flex items-center justify-between text-zinc-500 border-b border-white/[0.02] pb-1 mb-2 uppercase tracking-widest text-[8px]">
                      <span>Transmission Manifest Ledger</span>
                      <span className="text-emerald-400 font-bold">Γ£ô SECURED</span>
                    </div>
                    {logs.map((log, idx) => (
                      <div key={idx} className="flex gap-1.5 items-start">
                        <span className="text-emerald-400 select-none">&gt;</span>
                        <span className={idx === logs.length - 1 ? "text-emerald-400 font-bold" : "text-zinc-400"}>
                          {log}
                        </span>
                      </div>
                    ))}
                  </div>

                  {/* Close button resets form */}
                  <button
                    onClick={resetForm}
                    className="w-full py-3.5 rounded-lg border border-white/[0.05] hover:border-zinc-700 bg-white/[0.01] hover:bg-white/[0.02] text-xs text-zinc-400 hover:text-white transition-all duration-300 font-mono tracking-widest uppercase cursor-pointer"
                  >
                    Transmit Another Request
                  </button>

                </motion.div>
              )}
            </AnimatePresence>

          </div>
        </div>

      </div>
    </section>
  );
}

